properties.query:
//source: https://techcommunity.microsoft.com/t5/azure-sentinel/ingestion-cost-spike-detection-playbook/ba-p/2591301
//https://docs.microsoft.com/azure/data-explorer/kusto/query/series-decompose-anomaliesfunction 
let watchlist_AS_SNTL_042_DataType = (_GetWatchlist('watchlist_AS_SNTL_042_DataType') | project SearchKey);
let UpperAnomalyThreshold = 3;//Variable definida para comparar un aumento de datos anomalos
let DownAnomalyThreshold = -2;//Variable definida para comparar un decremento de datos anomalos
let ReportingQty = 0;//Variable definida para establecer cuanto MBs de consumo es una anomalia.
let PercentIncrease = 40;// Variable definida para establecer un porcentaje positivo el cual se considera un incremento de datos de una tabla
let PercentDecrease = -40;// Variable definida para establecer un porcentaje negativo el cual se considera un decremento de datos de una tabla
//let UpperThreshold = UpperAnomalyThreshold; //+3 es el número sugerido e indica una anomalía fuerte aunque se puede modificar
Usage
| where DataType !in (watchlist_AS_SNTL_042_DataType)
//| where IsBillable == "true" // Para tener en cuenta aquellas tablas que tienen costes.
| where Quantity > ReportingQty //Solo tiene en cuenta las variaciones que superen un determinado umbral que considere lo suficientemente significativo en MBs.
| make-series Qty=sum(Quantity) on TimeGenerated from ago(30d) to now() step 1d by DataType //Crea una serie temporal para observar el patrón de ingestión durante el periodo definido en la variable de tiempo, agrega los datos por dia durantes os ultimos 30 dias agrupando por el campo "Datatype".
| extend (anomalies, score, baseline) = series_decompose_anomalies(Qty, 1.5, 7, 'linefit', 1, 'ctukey', 0.01)
//Crea una columna con la función series_decompose_anomalies, la cual esta definida con los siguientes parámetros:
//Umbral de anomalia definido: 1.5//Umbral de sensibilidad para detectar anomalías. Son validos tanto valores positivos como negativos y el punto de partida es el valor indicado y compara con la columna score.
//Estacionalidad definido: 7 Número de puntos (en días) usados para detectar patrones cíclicos o estacionales,como los datos se agrupan por día (step 1d), se están considerando 7 días, útil para analizar patrones semanales.
//Tendencia: linefit//Método utilizado para ajustar la tendencia. y = mx + b
// y es el valor esperado de Qty (ingestión estimada)
// x es el tiempo
// m es la pendiente (si los datos suben o bajan)
// b es el punto de inicio
//Una vez se obtiene esa línea, se comparan los valores reales (Qty) contra esa línea estimada en cada punto.
//Si un valor está muy por encima o por debajo de la línea (más allá del umbral), se considera una anomalía.
//Puntos de prueba: 1//Indica si se elimina el componente estacional, el valor 1 significa que sí se elimina, para centrarse únicamente en tendencias y anomalías netas.
//Metodo AD: ctukey//Método estadístico para detectar anomalías.
//Umbral Estacionalidad:0.01//Nivel de significancia estadística (probabilidad de que una anomalía detectada lo sea realmente), el valor 0.01 significa alta confianza (99%) en los resultados,si pusieras 0.05,aceptarías más anomalías potenciales, pero con menos certeza.
// La salida de todos estos valores va dividida por las columnas "anomalies", "score" y "baseline"
//anomalies: Una serie ternaria que contiene (+1, -1, 0) marcando respectivamente anomalía arriba/abajo/no anomalía
//score: Puntuación anomalia
//baseline: El valor previsto de la serie, según la descomposición
| where anomalies[-1] == 1 or anomalies[-1] == -1 //La salida de la columna "anomalies" tiene tiene los siguientes valores:(+1, -1, 0) marcando respectivamente anomalía arriba/abajo/no anomalía y indica esta anomalia con la ultima posicion del array.
| extend Score = score[-1] //Esta parte recoge el estado de anomalía de la ejecución más reciente. -1 indica una posición en la matriz la cual indica el ultima valor del array.
| where Score >= UpperAnomalyThreshold or Score <= DownAnomalyThreshold//Compara el valor de "Score" con las variables definidas para detectar desviaciones incrementales y decrementales
| extend PercentageQty = ((round(todouble(Qty[-1]),0)-round(todouble(baseline[-1]),1))/round(todouble(Qty[-1]),0) * 100) //Calcula el incremento porcentual para presentar los datos en términos porcentuales y facilitar la apreciación de la anomalía.
| project DataType,ExpectedQty=round(todouble(baseline[-1]),0), ActualQty=round(todouble(Qty[-1]),0),round(PercentageQty,0)  
| order by round(todouble(PercentageQty),0) desc 
| where PercentageQty >= PercentIncrease or PercentageQty<=PercentDecrease//Sólo alerta si el porcentaje de incremento o decremento supera el umbral a partir del cual especificó que desea ser notificado en las variables definidas.
| extend PercentageIncrease= iff(PercentageQty >= PercentIncrease,tostring(PercentageQty),"N/A")//Crea una columna llamada "PercentageIncrease" si el porcentaje es positivo sino indica N/A.
| extend PercentageDecrease = iff(PercentageQty <= PercentDecrease,tostring(PercentageQty),"N/A")//Crea una columna llamada "PercentageDecrease" si el porcentaje es negativo sino indica N/A.
| where PercentageQty != "-Infinity" and ExpectedQty > 0//Filtra valores que sean "-Infinity" o valores mayor a cero en la columna "ExpectedQty"
| project Object = DataType, ActualQty, ExpectedQty, PercentageQty, PercentageIncrease, PercentageDecrease
